mapper.select:
SELECT

FROM consultation_record
WHERE uid = #{uid}

    AND urgency = #{urgency}


    AND (
        title LIKE CONCAT('%', #{keyword}, '%')
        OR summary LIKE CONCAT('%', #{keyword}, '%')
    )


    AND ended_at >= #{startAt}


    AND ended_at <= #{endAt}

ORDER BY ended_at DESC, generated_at DESC
